module.render:
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const mins = parseInt(args.minutes, 10) || 0;
const secs = parseInt(args.seconds, 10) || 0;
let total = mins * 60 + secs;
if (!total) total = 300;
const autostart = (args.autostart === 'true' || args.autostart === '1') ? 'true' : 'false';
const sizes = { sm: 'sm', md: 'md', lg: 'lg', xl: 'xl' };
const size = sizes[(args.size || 'md').toLowerCase()] || 'md';
// Appearance: shape (corner style / no box), background, border, text colour.
// Each is optional — omitted args fall back to the stylesheet defaults.
const shape = String(args.shape || 'rounded').toLowerCase();
const st = [];
if (args.bg) st.push('background:' + args.bg);
else if (shape === 'none') st.push('background:transparent');
if (args.border) st.push('border:1.5px solid ' + args.border);
if (args.color) st.push('color:' + args.color);
const radius = shape === 'pill' ? '999px' : (shape === 'square' || shape === 'none') ? '0' : '0.5em';
st.push('border-radius:' + radius);
if (shape === 'none') st.push('padding:0');
// Alignment (visible when placed/lifted in Edit layout). Default center
// reproduces the original lifted layout.
const alignKey = String(args.align || 'center').toLowerCase();
const justify = alignKey === 'left' ? 'flex-start' : alignKey === 'right' ? 'flex-end' : 'center';
st.push('justify-content:' + justify);
const styleAttr = st.length ? ' style="' + st.join(';') + '"' : '';
// Optional caption + optional controls.
const label = (args.label || '').trim();
const labelHtml = label ? '<span class="mdp-timer-label">' + esc(label) + '</span>' : '';
const controls = String(args.controls) !== 'false';
const wrapCls = 'mdp-mod-timer mdp-interactive mdp-size-' + size + (controls ? '' : ' mdp-timer-nocontrols');
const mm = String(Math.floor(total / 60)).padStart(2, '0');
const ss = String(total % 60).padStart(2, '0');
// Fix the display width to the initial digit count (the value only counts
// down, so this is the widest it ever gets) — the box never reflows / jitters.
const chars = mm.length + 1 + ss.length;
return '<span class="' + wrapCls + '"' + styleAttr + ' data-seconds="' + total + '" data-autostart="' + autostart + '">'
  + labelHtml
  + '<button class="mdp-timer-btn mdp-timer-start" type="button" title="Start / Pause">&#9654;</button>'
  + '<span class="mdp-timer-display" style="width:' + chars + 'ch">' + mm + ':' + ss + '</span>'
  + '<button class="mdp-timer-btn mdp-timer-reset" type="button" title="Reset">&#8634;</button>'
  + '</span>';

module.script:
export default {
  init(el, ctx) {
    const display = el.querySelector('.mdp-timer-display');
    const startBtn = el.querySelector('.mdp-timer-start');
    const resetBtn = el.querySelector('.mdp-timer-reset');
    const total = parseInt(el.dataset.seconds, 10) || 300;

    const fmt = function (s) {
      s = Math.max(0, s);
      return String(Math.floor(s / 60)).padStart(2, '0') + ':' + String(s % 60).padStart(2, '0');
    };
    const paint = function (state) {
      const st = state || ctx.getShared() || { remaining: total, running: false, done: false };
      const remaining = (typeof st.remaining === 'number') ? st.remaining : total;
      display.textContent = fmt(remaining);
      startBtn.innerHTML = st.running ? '&#10073;&#10073;' : '&#9654;';
      el.classList.toggle('mdp-timer-done', !!st.done);
    };

    // Every surface re-renders on shared-state changes and routes clicks
    // through actions (the owner is the single source of truth).
    ctx.onShared(paint);
    startBtn.addEventListener('click', function () { ctx.sendAction('toggle'); });
    resetBtn.addEventListener('click', function () { ctx.sendAction('reset'); });

    if (ctx.role === 'owner') {
      let timer = null;
      const get = function () { return ctx.getShared() || { remaining: total, running: false, done: false }; };
      const stopInterval = function () { if (timer) { clearInterval(timer); timer = null; } };
      const startInterval = function () {
        if (timer) return;
        timer = setInterval(function () {
          const st = get();
          const next = (typeof st.remaining === 'number' ? st.remaining : total) - 1;
          if (next <= 0) { stopInterval(); ctx.setShared({ remaining: 0, running: false, done: true }); }
          else { ctx.setShared({ remaining: next }); }
        }, 1000);
      };

      // Initialise the shared state once (first owner to mount wins).
      if (!ctx.getShared()) ctx.setShared({ remaining: total, running: false, done: false });

      ctx.onAction(function (type) {
        const st = get();
        if (type === 'toggle') {
          if (st.running) { stopInterval(); ctx.setShared({ running: false }); }
          else if ((typeof st.remaining === 'number' ? st.remaining : total) > 0) {
            ctx.setShared({ running: true, done: false }); startInterval();
          }
        } else if (type === 'reset') {
          stopInterval(); ctx.setShared({ remaining: total, running: false, done: false });
        }
      });

      // Resume ticking if state says we are mid-run (owner re-mounted), then
      // honour autostart in the slideshow.
      if (get().running) startInterval();
      else if (ctx.presenting && el.dataset.autostart === 'true' && !get().done) {
        ctx.setShared({ running: true, done: false }); startInterval();
      }

      ctx.onCleanup(stopInterval);
    }

    paint();
  }
}
